#include <iostream>
#include <vector>
#include <algorithm>
#include <string>
#include <numeric>

struct Player {
    std::string name;
    int score;
    int level;
};

int main() {
    std::cout << "=== STL Algorithms — sort, find, count ===" << std::endl;

    // 1. Sorting
    std::cout << "\n--- Sorting ---" << std::endl;
    std::vector<int> scores = {45, 23, 89, 12, 56, 78, 34};

    std::cout << "Original: ";
    for (int s : scores) std::cout << s << " ";
    std::cout << std::endl;

    std::sort(scores.begin(), scores.end());
    std::cout << "Sorted (ascending): ";
    for (int s : scores) std::cout << s << " ";
    std::cout << std::endl;

    std::sort(scores.begin(), scores.end(), std::greater<int>());
    std::cout << "Sorted (descending): ";
    for (int s : scores) std::cout << s << " ";
    std::cout << std::endl;

    // 2. Finding
    std::cout << "\n--- Finding ---" << std::endl;
    auto it = std::find(scores.begin(), scores.end(), 56);
    if (it != scores.end()) {
        std::cout << "Found 56 at position: " << (it - scores.begin()) << std::endl;
    } else {
        std::cout << "56 not found" << std::endl;
    }

    it = std::find(scores.begin(), scores.end(), 100);
    if (it != scores.end()) {
        std::cout << "Found 100" << std::endl;
    } else {
        std::cout << "100 not found" << std::endl;
    }

    // 3. Counting
    std::cout << "\n--- Counting ---" << std::endl;
    std::vector<int> numbers = {1, 2, 3, 2, 4, 2, 5, 2, 6};

    int count2 = std::count(numbers.begin(), numbers.end(), 2);
    std::cout << "Number of 2s: " << count2 << std::endl;

    // 4. Count with condition
    int countEven = std::count_if(numbers.begin(), numbers.end(), 
                                   [](int n) { return n % 2 == 0; });
    std::cout << "Number of evens: " << countEven << std::endl;

    // 5. Min and Max
    std::cout << "\n--- Min and Max ---" << std::endl;
    auto [min, max] = std::minmax_element(scores.begin(), scores.end());
    std::cout << "Min: " << *min << ", Max: " << *max << std::endl;

    // 6. Copy
    std::cout << "\n--- Copy ---" << std::endl;
    std::vector<int> source = {1, 2, 3, 4, 5};
    std::vector<int> dest(source.size());

    std::copy(source.begin(), source.end(), dest.begin());
    std::cout << "Copied: ";
    for (int n : dest) std::cout << n << " ";
    std::cout << std::endl;

    // 7. Game use: sorting players by score
    std::cout << "\n--- Leaderboard (sort by score) ---" << std::endl;
    std::vector<Player> players = {
        {"Hero", 100, 5},
        {"Aragorn", 85, 4},
        {"Gandalf", 95, 5},
        {"Legolas", 90, 4}
    };

    std::sort(players.begin(), players.end(),
              [](const Player& a, const Player& b) {
                  return a.score > b.score;  // Descending
              });

    std::cout << "Leaderboard:" << std::endl;
    for (const Player& p : players) {
        std::cout << "  " << p.name << ": " << p.score << " (Level " << p.level << ")" << std::endl;
    }

    // 8. Finding a player
    auto found = std::find_if(players.begin(), players.end(),
                               [](const Player& p) { return p.name == "Gandalf"; });
    if (found != players.end()) {
        std::cout << "\nFound Gandalf! Score: " << found->score << std::endl;
    }

    std::cout << "\n--- Common STL Algorithms ---" << std::endl;
    std::cout << "✅ sort, find, count, count_if" << std::endl;
    std::cout << "✅ min_element, max_element" << std::endl;
    std::cout << "✅ copy, reverse, rotate" << std::endl;
    std::cout << "✅ accumulate, for_each, transform" << std::endl;

    return 0;
}

