#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::vector<int> numbers = {15, 3, 22, 8, 15, 3, 10, 15};

    std::cout << "Original: ";
    for (int n : numbers) std::cout << n << " ";
    std::cout << std::endl;

    std::sort(numbers.begin(), numbers.end());
    std::cout << "Sorted: ";
    for (int n : numbers) std::cout << n << " ";
    std::cout << std::endl;

    int count15 = std::count(numbers.begin(), numbers.end(), 15);
    std::cout << "\nNumber of 15s: " << count15 << std::endl;

    auto it = std::find(numbers.begin(), numbers.end(), 10);
    if (it != numbers.end()) {
        std::cout << "10 found at position: " << (it - numbers.begin()) << std::endl;
    }

    auto [min, max] = std::minmax_element(numbers.begin(), numbers.end());
    std::cout << "Min: " << *min << ", Max: " << *max << std::endl;

    numbers.erase(std::remove(numbers.begin(), numbers.end(), 3), numbers.end());
    std::cout << "\nAfter removing 3s: ";
    for (int n : numbers) std::cout << n << " ";
    std::cout << std::endl;

    return 0;
}
